#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int findContentChildren(int* student, int studentSize, int* cookie, int cookieSize) {
    qsort(student, studentSize, sizeof(int), compare);
    qsort(cookie, cookieSize, sizeof(int), compare);
    int i = 0, j = 0;
    while (i < studentSize && j < cookieSize) {
        if (cookie[j] >= student[i]) {
            i++;
        }
        j++;
    }
    return i;
}

int main() {
    int student[] = {1, 2, 3};
    int cookie[] = {1, 2, 3};
    int studentSize = sizeof(student) / sizeof(student[0]);
    int cookieSize = sizeof(cookie) / sizeof(cookie[0]);
    printf("%d\n", findContentChildren(student, studentSize, cookie, cookieSize));
    return 0;
}

