        Arrays.sort(student);
        Arrays.sort(cookie);
        int i = 0, j = 0;
        while (i < student.length && j < cookie.length) {
            if (cookie[j] >= student[i]) {
                i++;
            }
            j++;
        }
        return i;
    }
}

class Main {
    public static void main(String[] args) {
        int[] student = {1, 2, 3};
        int[] cookie = {1, 2, 3};
        Solution solver = new Solution();
        System.out.println(solver.findContentChildren(student, cookie));
    }
}

