class Solution {
    findContentChildren(student, cookie) {
        student.sort((a, b) => a - b);
        cookie.sort((a, b) => a - b);
        let i = 0;
        for (let j = 0; j < cookie.length; j++) {
            if (i < student.length && cookie[j] >= student[i]) {
                i++;
            }
        }
        return i;
    }
}

